import sys
from typing import Optional
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
class Solution:
    def maxDepth(self, root: Optional[TreeNode]) -> int:
        if not root:
            return 0
        return 1 + max(self.maxDepth(root.left), self.maxDepth(root.right))
if __name__ == '__main__':
    def read_ints():
        return map(int, sys.stdin.read().split())
    it = iter(read_ints())
    try:
        val = next(it)
        root = None
        nodes = []
        for _ in range(val):
            node_val = next(it)
            node = TreeNode(node_val)
            nodes.append(node)
        for i in range(val):
            node = nodes[i]
            left_child_idx = 2 * i + 1
            if left_child_idx < val:
                node.left = nodes[left_child_idx]
            right_child_idx = 2 * i + 2
            if right_child_idx < val:
                node.right = nodes[right_child_idx]
        root = nodes[0]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.maxDepth(root)
    print(ans)

