#include <numeric>
#include <iostream>
#include <vector>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
class Solution {
public:
    int maxDepth(TreeNode* root) {
        if (!root) return 0;
        return 1 + max(maxDepth(root->left), maxDepth(root->right));
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; i++) {
        int val;
        cin >> val;
        nodes[i] = new TreeNode(val);
    }
    for (int i = 0; i < n; i++) {
        int left_child_idx = 2 * i + 1;
        if (left_child_idx < n) nodes[i]->left = nodes[left_child_idx];
        int right_child_idx = 2 * i + 2;
        if (right_child_idx < n) nodes[i]->right = nodes[right_child_idx];
    }
    Solution sol;
    int ans = sol.maxDepth(nodes[0]);
    cout << ans << endl;
    return 0;
}
